--
-- Table structure for table `vaccinations`
--

DROP TABLE IF EXISTS `vaccinations`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `vaccinations` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `lapereau_id` bigint unsigned NOT NULL,
  `type` enum('myxomatose','vhd','pasteurellose','coccidiose','autre') COLLATE utf8mb4_unicode_ci NOT NULL,
  `nom_personnalise` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL COMMENT 'Si type = autre',
  `date_administration` date NOT NULL,
  `dose_numero` tinyint unsigned NOT NULL DEFAULT '1',
  `rappel_prevu` date DEFAULT NULL,
  `rappel_notified` tinyint(1) NOT NULL DEFAULT '0',
  `notes` text COLLATE utf8mb4_unicode_ci,
  `administered_by` bigint unsigned DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `vaccinations_administered_by_foreign` (`administered_by`),
  KEY `vaccinations_lapereau_id_date_administration_index` (`lapereau_id`,`date_administration`),
  KEY `vaccinations_type_index` (`type`),
  CONSTRAINT `vaccinations_administered_by_foreign` FOREIGN KEY (`administered_by`) REFERENCES `users` (`id`),
  CONSTRAINT `vaccinations_lapereau_id_foreign` FOREIGN KEY (`lapereau_id`) REFERENCES `lapereaux` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

